package main

import "fmt"

func main() {
    // ---- len and cap ----
    fmt.Println("=== len and cap ===")
    s := make([]int, 3, 5)
    fmt.Printf("s: %v, len: %d, cap: %d\n", s, len(s), cap(s))

    // ---- append with capacity ----
    fmt.Println("\n=== Append with capacity ===")
    s2 := make([]int, 0, 3)
    fmt.Printf("Initial: len=%d, cap=%d\n", len(s2), cap(s2))

    for i := 1; i <= 5; i++ {
        s2 = append(s2, i)
        fmt.Printf("After append %d: len=%d, cap=%d\n", i, len(s2), cap(s2))
    }

    // ---- Append with nil slice ----
    fmt.Println("\n=== Nil slice append ===")
    var s3 []int
    fmt.Printf("Before: s3 == nil: %t\n", s3 == nil)
    s3 = append(s3, 1, 2, 3)
    fmt.Printf("After append: %v\n", s3)

    // ---- Slice capacity doubling ----
    fmt.Println("\n=== Capacity doubling ===")
    s4 := make([]int, 0, 1)
    for i := 0; i < 10; i++ {
        s4 = append(s4, i)
        fmt.Printf("len=%d, cap=%d\n", len(s4), cap(s4))
    }

    // ---- Append multiple elements ----
    fmt.Println("\n=== Append multiple ===")
    s5 := []int{1, 2, 3}
    s5 = append(s5, 4, 5, 6)
    fmt.Println(s5)

    // ---- Append a slice ----
    fmt.Println("\n=== Append slice ===")
    s6 := []int{1, 2, 3}
    s7 := []int{4, 5, 6}
    s6 = append(s6, s7...)
    fmt.Println(s6)

    // ---- Slice as function parameter ----
    fmt.Println("\n=== Slice as parameter ===")
    nums := []int{1, 2, 3}
    modifySlice(nums)
    fmt.Println("After function:", nums)

    // ---- Slice with pre-allocation ----
    fmt.Println("\n=== Pre-allocation ===")
    // Better: Pre-allocate to avoid reallocations
    size := 1000
    s8 := make([]int, 0, size)
    for i := 0; i < size; i++ {
        s8 = append(s8, i)
    }
    fmt.Printf("Final len=%d, cap=%d\n", len(s8), cap(s8))
}

func modifySlice(s []int) {
    s[0] = 99
}

