phase3.solution:
package main

import "fmt"

func main() {
    s := make([]int, 0, 3)

    for i := 1; i <= 5; i++ {
        s = append(s, i)
        fmt.Printf("After append %d: len=%d, cap=%d\n", i, len(s), cap(s))
    }

    fmt.Println("Final slice:", s)
}
